import React, { useState, useEffect } from 'react';

function App() {
  const [books, setBooks] = useState([]);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [cart, setCart] = useState([]);

  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authMode, setAuthMode] = useState('login');
  const [authError, setAuthError] = useState(null);

  const [showCheckoutModal, setShowCheckoutModal] = useState(false);

  const [sortBy, setSortBy] = useState('none');
  const [currentPage, setCurrentPage] = useState(1);
  const booksPerPage = 10;

  const [isAdmin, setIsAdmin] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newAuthor, setNewAuthor] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newCategory, setNewCategory] = useState('Stories');
  const [showAddModal, setShowAddModal] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      fetch('http://localhost:5000/api/products')
        .then(res => {
          if (!res.ok) {
            throw new Error('Server returned status: ' + res.status);
          }
          return res.json();
        })
        .then(data => setBooks(data))
        .catch(err => {
          console.error(err);
          setError('Failed to load books: ' + err.message);
        });
    }
  }, [isLoggedIn]);

  const handleAuth = (e) => {
    e.preventDefault();
    setAuthError(null);

    if (authMode === 'login') {
      if (email === 'admin@deci.com' && password === '0000') {
        setIsAdmin(true);
        setUsername('Admin');
        setIsLoggedIn(true);
        return;
      }

      fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      })
        .then(res => {
          if (!res.ok) {
            throw new Error('Invalid email or password');
          }
          return res.json();
        })
        .then(data => {
          if (email === 'admin@deci.com') {
            setIsAdmin(true);
            setUsername('Admin');
          } else {
            const nameFromEmail = email.split('@')[0];
            setUsername(nameFromEmail.charAt(0).toUpperCase() + nameFromEmail.slice(1));
          }
          setIsLoggedIn(true);
        })
        .catch(err => {
          setAuthError(err.message);
        });
    } else {
      if (username.trim() === '') {
        setAuthError('Please enter a username');
        return;
      }
      setIsLoggedIn(true);
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdmin(false);
    setEmail('');
    setPassword('');
    setCart([]);
    if (authMode === 'login') setUsername('');
  };

  const addToCart = (book) => {
    setCart([...cart, book]);
  };

  const removeFromCart = (indexToRemove) => {
    setCart(cart.filter((_, index) => index !== indexToRemove));
  };

  const confirmCheckout = () => {
    setCart([]);
    setShowCheckoutModal(false);
  };

  const handleAddBook = (e) => {
    e.preventDefault();
    
    const newBookId = Date.now(); 
    const bookData = { 
      id: newBookId, 
      title: newTitle, 
      author: newAuthor, 
      price: parseFloat(newPrice), 
      category: newCategory 
    };
    
    setBooks([...books, bookData]);
    setShowAddModal(false);
    setNewTitle(''); 
    setNewAuthor(''); 
    setNewPrice('');

    fetch('http://localhost:5000/api/products', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: newTitle,
        author: newAuthor,
        price: parseFloat(newPrice),
        category: newCategory
      })
    })
    .then(res => {
      if (!res.ok) console.error('Server failed to save, but added locally');
      return res.json();
    })
    .catch(err => console.error('Network error, book kept locally:', err));
  };

  const handleDeleteBook = (id) => {
    fetch(`http://localhost:5000/api/products/${id}`, { method: 'DELETE' })
      .then(() => {
        setBooks(books.filter(book => book.id !== id));
      });
  };

  const cartTotal = cart.reduce((total, book) => total + book.price, 0);

  const filtered = books.filter(book => {
    const matchesSearch = book.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          book.author.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || book.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const sortedBooks = [...filtered].sort((a, b) => {
    if (sortBy === 'low-to-high') return a.price - b.price;
    if (sortBy === 'high-to-low') return b.price - a.price;
    return 0;
  });

  const indexOfLastBook = currentPage * booksPerPage;
  const indexOfFirstBook = indexOfLastBook - booksPerPage;
  const currentBooks = sortedBooks.slice(indexOfFirstBook, indexOfLastBook);
  const totalPages = Math.ceil(sortedBooks.length / booksPerPage);

  if (!isLoggedIn) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', backgroundColor: '#0b0f19', backgroundImage: 'radial-gradient(circle at 10% 20%, rgba(30, 41, 59, 0.4) 0%, transparent 80%)', fontFamily: '"Inter", system-ui, -apple-system, sans-serif' }}>
        <form onSubmit={handleAuth} style={{ backgroundColor: 'rgba(23, 32, 53, 0.75)', backdropFilter: 'blur(16px)', WebkitBackdropFilter: 'blur(16px)', padding: '40px', borderRadius: '24px', border: '1px solid rgba(255, 255, 255, 0.08)', boxShadow: '0 20px 40px rgba(0,0,0,0.4)', width: '100%', maxWidth: '380px', transition: 'all 0.3s ease' }}>
          <h2 style={{ textAlign: 'center', color: '#ffffff', marginBottom: '8px', fontSize: '28px', fontWeight: '800', letterSpacing: '-0.5px' }}>
            {authMode === 'login' ? 'Welcome Back' : 'Create Account'}
          </h2>
          <p style={{ textAlign: 'center', color: '#94a3b8', fontSize: '14px', marginBottom: '32px', marginTop: '0' }}>
            {authMode === 'login' ? 'Sign in to access your digital library' : 'Get started with Z-BOOK Store today'}
          </p>
          
          {authError && (
            <div style={{ color: '#fda4af', backgroundColor: 'rgba(225, 29, 72, 0.15)', border: '1px solid rgba(225, 29, 72, 0.3)', padding: '12px', borderRadius: '12px', textAlign: 'center', marginBottom: '20px', fontWeight: '500', fontSize: '14px' }}>
              {authError}
            </div>
          )}

          {authMode === 'signup' && (
            <div style={{ marginBottom: '20px' }}>
              <label htmlFor="username-input" style={{ display: 'block', marginBottom: '8px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', letterSpacing: '0.5px', textTransform: 'uppercase' }}>Username</label>
              <input 
                id="username-input"
                type="text" 
                required
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                style={{ width: '100%', padding: '12px 16px', borderRadius: '12px', border: '1px solid rgba(255, 255, 255, 0.1)', backgroundColor: 'rgba(15, 23, 42, 0.6)', color: '#fff', outline: 'none', boxSizing: 'border-box', fontSize: '15px', transition: 'all 0.2s ease', focus: { border: '1px solid #6366f1' } }}
              />
            </div>
          )}

          <div style={{ marginBottom: '20px' }}>
            <label htmlFor="email-input" style={{ display: 'block', marginBottom: '8px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', letterSpacing: '0.5px', textTransform: 'uppercase' }}>Email Address</label>
            <input 
              id="email-input"
              type="email" 
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              style={{ width: '100%', padding: '12px 16px', borderRadius: '12px', border: '1px solid rgba(255, 255, 255, 0.1)', backgroundColor: 'rgba(15, 23, 42, 0.6)', color: '#fff', outline: 'none', boxSizing: 'border-box', fontSize: '15px', transition: 'all 0.2s ease' }}
            />
          </div>

          <div style={{ marginBottom: '32px' }}>
            <label htmlFor="password-input" style={{ display: 'block', marginBottom: '8px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', letterSpacing: '0.5px', textTransform: 'uppercase' }}>Password</label>
            <input 
              id="password-input"
              type="password" 
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              style={{ width: '100%', padding: '12px 16px', borderRadius: '12px', border: '1px solid rgba(255, 255, 255, 0.1)', backgroundColor: 'rgba(15, 23, 42, 0.6)', color: '#fff', outline: 'none', boxSizing: 'border-box', fontSize: '15px', transition: 'all 0.2s ease' }}
            />
          </div>

          <button type="submit" style={{ width: '100%', background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', color: '#fff', border: 'none', padding: '14px', borderRadius: '12px', cursor: 'pointer', fontWeight: '600', fontSize: '16px', marginBottom: '24px', boxShadow: '0 4px 12px rgba(79, 70, 229, 0.3)', transition: 'transform 0.2s, opacity 0.2s' }}>
            {authMode === 'login' ? 'Sign In' : 'Get Started'}
          </button>

          <p style={{ textAlign: 'center', margin: 0, fontSize: '14px', color: '#94a3b8' }}>
            {authMode === 'login' ? "New to Z-BOOK? " : "Have an account? "}
            <span 
              onClick={() => { setAuthMode(authMode === 'login' ? 'signup' : 'login'); setAuthError(null); }}
              style={{ color: '#818cf8', cursor: 'pointer', fontWeight: '600', textDecoration: 'none', marginLeft: '4px' }}
            >
              {authMode === 'login' ? 'Create one' : 'Sign in'}
            </span>
          </p>
        </form>
      </div>
    );
  }

  return (
    <div style={{ padding: '40px', fontFamily: '"Inter", system-ui, -apple-system, sans-serif', backgroundColor: '#0f172a', color: '#f8fafc', minHeight: '100vh', display: 'flex', flexDirection: 'column', gap: '32px' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: 'rgba(30, 41, 59, 0.5)', backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)', padding: '20px 40px', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', boxShadow: '0 4px 20px rgba(0,0,0,0.15)' }}>
        <h1 style={{ color: '#ffffff', margin: 0, fontSize: '26px', fontWeight: '800', letterSpacing: '-0.5px', background: 'linear-gradient(to right, #ffffff, #94a3b8)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>Z-BOOK<span style={{ color: '#6366f1', WebkitTextFillColor: 'initial' }}>.</span></h1>
        <div style={{ display: 'flex', alignItems: 'center', gap: '24px' }}>
          <span style={{ fontWeight: '500', color: '#94a3b8', fontSize: '15px' }}>Logged in as <span style={{ color: '#fff', fontWeight: '600' }}>{username}</span></span>
          <button onClick={handleLogout} style={{ backgroundColor: 'rgba(239, 68, 68, 0.1)', color: '#ef4444', border: '1px solid rgba(239, 68, 68, 0.2)', padding: '10px 20px', borderRadius: '12px', cursor: 'pointer', fontWeight: '600', fontSize: '14px', transition: 'all 0.2s ease' }}>Logout</button>
        </div>
      </div>

      {isAdmin ? (
        <div style={{ width: '100%', maxWidth: '1200px', margin: '0 auto', backgroundColor: 'rgba(30, 41, 59, 0.4)', padding: '40px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', boxShadow: '0 12px 40px rgba(0,0,0,0.2)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
            <div>
              <h2 style={{ margin: 0, color: '#fff', fontSize: '24px', fontWeight: '700' }}>Admin Console</h2>
              <p style={{ margin: '4px 0 0 0', color: '#94a3b8', fontSize: '14px' }}>Manage and monitor the digital store catalogue</p>
            </div>
            <button onClick={() => setShowAddModal(true)} style={{ background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', color: '#fff', border: 'none', padding: '12px 24px', borderRadius: '12px', cursor: 'pointer', fontWeight: '600', fontSize: '15px', boxShadow: '0 4px 12px rgba(16, 185, 129, 0.2)' }}>Add Premium Book</button>
          </div>

          <div style={{ overflowX: 'auto', borderRadius: '16px', border: '1px solid rgba(255,255,255,0.05)' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', backgroundColor: 'rgba(15, 23, 42, 0.3)' }}>
              <thead>
                <tr style={{ backgroundColor: 'rgba(15, 23, 42, 0.6)', borderBottom: '1px solid rgba(255,255,255,0.08)' }}>
                  <th style={{ padding: '18px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Title</th>
                  <th style={{ padding: '18px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Author</th>
                  <th style={{ padding: '18px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Category</th>
                  <th style={{ padding: '18px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Price</th>
                  <th style={{ padding: '18px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px', textAlign: 'right' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {books.map(book => (
                  <tr key={book.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.04)', transition: 'background-color 0.2s' }}>
                    <td style={{ padding: '20px 24px', fontWeight: '600', color: '#ffffff', fontSize: '15px' }}>{book.title}</td>
                    <td style={{ padding: '20px 24px', color: '#94a3b8', fontSize: '15px' }}>{book.author}</td>
                    <td style={{ padding: '20px 24px' }}>
                      <span style={{ backgroundColor: 'rgba(99, 102, 241, 0.15)', color: '#818cf8', padding: '4px 10px', borderRadius: '8px', fontSize: '12px', fontWeight: '600' }}>{book.category}</span>
                    </td>
                    <td style={{ padding: '20px 24px', color: '#34d399', fontWeight: '700', fontSize: '16px' }}>${book.price.toFixed(2)}</td>
                    <td style={{ padding: '20px 24px', textAlign: 'right' }}>
                      <button onClick={() => handleDeleteBook(book.id)} style={{ backgroundColor: 'rgba(239, 68, 68, 0.1)', color: '#f87171', border: '1px solid rgba(239, 68, 68, 0.2)', padding: '8px 16px', borderRadius: '10px', cursor: 'pointer', fontWeight: '600', fontSize: '13px', transition: 'all 0.2s ease' }}>Remove</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          
          {books.length === 0 && (
            <div style={{ textAlign: 'center', padding: '60px 20px', color: '#64748b' }}>
              <p style={{ margin: 0, fontSize: '16px' }}>The store directory is currently empty.</p>
            </div>
          )}
        </div>
      ) : (
        <div style={{ display: 'flex', gap: '40px', alignItems: 'flex-start' }}>
          
          <div style={{ flex: '1' }}>
            {error && (
              <div style={{ color: '#fda4af', backgroundColor: 'rgba(225, 29, 72, 0.15)', border: '1px solid rgba(225, 29, 72, 0.2)', padding: '16px', borderRadius: '16px', textAlign: 'center', marginBottom: '32px', fontWeight: '600' }}>
                {error}
              </div>
            )}

            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '24px', marginBottom: '48px', backgroundColor: 'rgba(30, 41, 59, 0.2)', padding: '32px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.03)' }}>
              <div style={{ position: 'relative', width: '100%', maxWidth: '540px' }}>
                <input 
                  type="text" 
                  placeholder="Search architecture, design, history..." 
                  value={searchTerm}
                  onChange={(e) => { setSearchTerm(e.target.value); setCurrentPage(1); }}
                  style={{ 
                    padding: '16px 24px', 
                    width: '100%', 
                    borderRadius: '16px', 
                    border: '1px solid rgba(255, 255, 255, 0.08)', 
                    backgroundColor: 'rgba(15, 23, 42, 0.6)',
                    color: '#fff',
                    fontSize: '16px',
                    outline: 'none',
                    boxSizing: 'border-box',
                    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                    transition: 'all 0.2s ease'
                  }}
                />
              </div>

              <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap', justifyContent: 'center' }}>
                {['All', 'Stories', 'Science', 'History', 'Tech'].map(category => (
                  <button 
                    key={category}
                    onClick={() => { setSelectedCategory(category); setCurrentPage(1); }}
                    style={{
                      padding: '10px 24px',
                      borderRadius: '12px',
                      border: '1px solid rgba(255,255,255,0.04)',
                      cursor: 'pointer',
                      fontWeight: '600',
                      fontSize: '14px',
                      backgroundColor: selectedCategory === category ? '#6366f1' : 'rgba(30, 41, 59, 0.6)',
                      color: selectedCategory === category ? '#fff' : '#94a3b8',
                      boxShadow: selectedCategory === category ? '0 4px 12px rgba(99, 102, 241, 0.3)' : 'none',
                      transition: 'all 0.2s ease'
                    }}
                  >
                    {category}
                  </button>
                ))}
              </div>

              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginTop: '8px' }}>
                <label htmlFor="sort-select" style={{ fontSize: '14px', fontWeight: '500', color: '#64748b' }}>Sort By:</label>
                <select 
                  id="sort-select"
                  value={sortBy} 
                  onChange={(e) => { setSortBy(e.target.value); setCurrentPage(1); }}
                  style={{ padding: '8px 16px', borderRadius: '10px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.6)', color: '#fff', outline: 'none', cursor: 'pointer', fontSize: '14px' }}
                >
                  <option value="none">Default Sequence</option>
                  <option value="low-to-high">Price: Low to High</option>
                  <option value="high-to-low">Price: High to Low</option>
                </select>
              </div>
            </div>
            
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', 
              gap: '32px',
              width: '100%'
            }}>
              {currentBooks.map(book => (
                <div key={book.id} style={{ 
                  backgroundColor: 'rgba(30, 41, 59, 0.3)', 
                  padding: '24px', 
                  borderRadius: '20px', 
                  border: '1px solid rgba(255,255,255,0.04)',
                  display: 'flex', 
                  flexDirection: 'column', 
                  alignItems: 'center',
                  textAlign: 'center',
                  transition: 'transform 0.2s, box-shadow 0.2s'
                }}>
                  <div style={{ width: '100%', height: '240px', borderRadius: '12px', overflow: 'hidden', marginBottom: '20px', boxShadow: '0 8px 16px rgba(0,0,0,0.3)', backgroundColor: '#1e293b' }}>
                    <img 
                      src="https://images.unsplash.com/photo-1543002588-bfa74002ed7e?w=500&auto=format&fit=crop&q=60" 
                      alt="Book Cover" 
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                  </div>
                  <h3 style={{ margin: '0 0 6px 0', color: '#ffffff', fontSize: '17px', fontWeight: '700', height: '44px', overflow: 'hidden', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', lineHeight: '22px' }}>{book.title}</h3>
                  <p style={{ margin: '0 0 12px 0', color: '#64748b', fontSize: '14px', fontWeight: '500' }}>{book.author}</p>
                  <div style={{ marginTop: 'auto', width: '100%', display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <span style={{ backgroundColor: 'rgba(255,255,255,0.05)', color: '#94a3b8', padding: '4px 10px', borderRadius: '8px', fontSize: '11px', fontWeight: '600', textTransform: 'uppercase' }}>{book.category}</span>
                      <span style={{ fontWeight: '700', color: '#34d399', fontSize: '20px' }}>${book.price.toFixed(2)}</span>
                    </div>
                    <button 
                      onClick={() => addToCart(book)}
                      style={{ 
                        background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', 
                        color: '#fff', 
                        border: 'none', 
                        padding: '12px 16px', 
                        borderRadius: '12px', 
                        cursor: 'pointer', 
                        fontWeight: '600',
                        fontSize: '14px',
                        width: '100%',
                        boxShadow: '0 4px 12px rgba(79, 70, 229, 0.15)'
                      }}
                    >
                      Add to Cart
                    </button>
                  </div>
                </div>
              ))}
            </div>

            {currentBooks.length === 0 && (
              <p style={{ textAlign: 'center', color: '#64748b', fontSize: '16px', marginTop: '64px' }}>No curated items found matching criteria.</p>
            )}

            {totalPages > 1 && (
              <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '20px', marginTop: '48px' }}>
                <button 
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(prev => prev - 1)}
                  style={{ padding: '10px 20px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: currentPage === 1 ? 'transparent' : 'rgba(30, 41, 59, 0.6)', color: currentPage === 1 ? '#334155' : '#fff', cursor: currentPage === 1 ? 'not-allowed' : 'pointer', fontWeight: '600', fontSize: '14px' }}
                >
                  Previous
                </button>
                <span style={{ fontWeight: '600', color: '#64748b', fontSize: '14px' }}>{currentPage} / {totalPages}</span>
                <button 
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage(prev => prev + 1)}
                  style={{ padding: '10px 20px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: currentPage === totalPages ? 'transparent' : 'rgba(30, 41, 59, 0.6)', color: currentPage === totalPages ? '#334155' : '#fff', cursor: currentPage === totalPages ? 'not-allowed' : 'pointer', fontWeight: '600', fontSize: '14px' }}
                >
                  Next
                </button>
              </div>
            )}
          </div>

          <div style={{ 
            width: '340px', 
            backgroundColor: 'rgba(30, 41, 59, 0.4)', 
            padding: '32px', 
            borderRadius: '24px', 
            border: '1px solid rgba(255,255,255,0.05)', 
            position: 'sticky', 
            top: '40px',
            height: 'calc(100vh - 80px)',
            boxSizing: 'border-box',
            display: 'flex',
            flexDirection: 'column',
            boxShadow: '0 12px 40px rgba(0,0,0,0.15)'
          }}>
            <h2 style={{ color: '#fff', borderBottom: '1px solid rgba(255,255,255,0.08)', paddingBottom: '16px', marginTop: 0, fontSize: '20px', fontWeight: '700' }}>Review Order <span style={{ color: '#6366f1', fontSize: '16px', fontWeight: '500', marginLeft: '4px' }}>({cart.length})</span></h2>
            
            <div style={{ flex: 1, overflowY: 'auto', marginBottom: '24px', paddingRight: '4px' }}>
              {cart.length === 0 ? (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: '#64748b', fontSize: '14px' }}>
                  Your shopping bag is empty.
                </div>
              ) : (
                <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: '12px' }}>
                  {cart.map((item, index) => (
                    <li key={index} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: 'rgba(15, 23, 42, 0.3)', padding: '12px 16px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.02)' }}>
                      <div style={{ flex: 1, marginRight: '16px', overflow: 'hidden' }}>
                        <span style={{ overflow: 'hidden', whiteSpace: 'nowrap', textOverflow: 'ellipsis', display: 'block', fontWeight: '600', fontSize: '14px', color: '#fff' }}>{item.title}</span>
                        <span style={{ color: '#34d399', fontSize: '13px', fontWeight: '600' }}>${item.price.toFixed(2)}</span>
                      </div>
                      <button 
                        onClick={() => removeFromCart(index)}
                        style={{ backgroundColor: 'transparent', color: '#f87171', border: 'none', padding: '4px 8px', cursor: 'pointer', fontSize: '13px', fontWeight: '500' }}
                      >
                        Remove
                      </button>
                    </li>
                  ))}
                </ul>
              )}
            </div>

            <div style={{ borderTop: '1px solid rgba(255,255,255,0.08)', paddingTop: '20px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: '600', fontSize: '15px', marginBottom: '20px', color: '#94a3b8' }}>
                <span>Subtotal</span>
                <span style={{ color: '#34d399', fontSize: '20px', fontWeight: '700' }}>${cartTotal.toFixed(2)}</span>
              </div>
              <button 
                onClick={() => setShowCheckoutModal(true)}
                disabled={cart.length === 0}
                style={{ 
                  background: cart.length === 0 ? '#334155' : 'linear-gradient(135deg, #10b981 0%, #059669 100%)', 
                  color: cart.length === 0 ? '#64748b' : '#fff', 
                  border: 'none', 
                  padding: '16px', 
                  borderRadius: '14px', 
                  cursor: cart.length === 0 ? 'not-allowed' : 'pointer', 
                  fontWeight: '600',
                  width: '100%',
                  fontSize: '15px',
                  boxShadow: cart.length === 0 ? 'none' : '0 4px 12px rgba(16, 185, 129, 0.2)'
                }}
              >
                Secure Checkout
              </button>
            </div>
          </div>
        </div>
      )}

      {showCheckoutModal && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(15, 23, 42, 0.8)', backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 }}>
          <div style={{ backgroundColor: '#1e293b', border: '1px solid rgba(255,255,255,0.08)', padding: '40px', borderRadius: '24px', boxShadow: '0 24px 48px rgba(0,0,0,0.4)', width: '100%', maxWidth: '420px', textAlign: 'center' }}>
            <div style={{ color: '#10b981', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: '64px', height: '64px', backgroundColor: 'rgba(16, 185, 129, 0.1)', borderRadius: '50%', fontSize: '32px', marginBottom: '24px', fontWeight: 'bold' }}>✓</div>
            <h3 style={{ margin: '0 0 8px 0', color: '#fff', fontSize: '22px', fontWeight: '700' }}>Purchase Complete</h3>
            <p style={{ color: '#94a3b8', fontSize: '15px', marginBottom: '32px', marginTop: '0', lineHeight: '24px' }}>
              Thank you, <strong>{username}</strong>. Your collection of <strong>{cart.length}</strong> digital books has been authorized successfully for a total of <strong>${cartTotal.toFixed(2)}</strong>.
            </p>
            <button 
              onClick={confirmCheckout}
              style={{ background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', color: '#fff', border: 'none', padding: '12px 32px', borderRadius: '12px', cursor: 'pointer', fontWeight: '600', fontSize: '15px', boxShadow: '0 4px 12px rgba(79, 70, 229, 0.2)' }}
            >
              Back to Catalogues
            </button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(15, 23, 42, 0.8)', backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 }}>
          <form onSubmit={handleAddBook} style={{ backgroundColor: '#1e293b', border: '1px solid rgba(255,255,255,0.08)', padding: '40px', borderRadius: '24px', width: '100%', maxWidth: '400px', boxShadow: '0 24px 48px rgba(0,0,0,0.4)' }}>
            <h3 style={{ marginTop: 0, marginBottom: '24px', color: '#fff', fontSize: '20px', fontWeight: '700' }}>Index New Publication</h3>
            <div style={{ marginBottom: '20px' }}>
              <label htmlFor="new-title" style={{ display: 'block', marginBottom: '8px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Title</label>
              <input id="new-title" type="text" required value={newTitle} onChange={(e) => setNewTitle(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#fff', borderRadius: '12px', boxSizing: 'border-box', outline: 'none', fontSize: '15px' }} />
            </div>
            <div style={{ marginBottom: '20px' }}>
              <label htmlFor="new-author" style={{ display: 'block', marginBottom: '8px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Author</label>
              <input id="new-author" type="text" required value={newAuthor} onChange={(e) => setNewAuthor(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#fff', borderRadius: '12px', boxSizing: 'border-box', outline: 'none', fontSize: '15px' }} />
            </div>
            <div style={{ marginBottom: '20px' }}>
              <label htmlFor="new-price" style={{ display: 'block', marginBottom: '8px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Price ($)</label>
              <input id="new-price" type="number" step="0.01" required value={newPrice} onChange={(e) => setNewPrice(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#fff', borderRadius: '12px', boxSizing: 'border-box', outline: 'none', fontSize: '15px' }} />
            </div>
            <div style={{ marginBottom: '32px' }}>
              <label htmlFor="new-category" style={{ display: 'block', marginBottom: '8px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Category</label>
              <select id="new-category" value={newCategory} onChange={(e) => setNewCategory(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#fff', borderRadius: '12px', outline: 'none', cursor: 'pointer', fontSize: '15px' }}>
                <option value="Stories">Stories</option>
                <option value="Science">Science</option>
                <option value="History">History</option>
                <option value="Tech">Tech</option>
              </select>
            </div>
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px' }}>
              <button type="button" onClick={() => setShowAddModal(false)} style={{ padding: '12px 20px', background: 'transparent', border: '1px solid rgba(255,255,255,0.08)', color: '#94a3b8', borderRadius: '12px', cursor: 'pointer', fontWeight: '600', fontSize: '14px' }}>Cancel</button>
              <button type="submit" style={{ padding: '12px 20px', background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', color: '#fff', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: '600', fontSize: '14px' }}>Publish Item</button>
            </div>
          </form>
        </div>
      )}

    </div>
  );
}

export default App;
